using UnityEngine;
using UnityEditor;
using TowerDefense.Data;

string[] guids = AssetDatabase.FindAssets("t:EnemyData");
int count = 0;
foreach (string guid in guids)
{
    string path = AssetDatabase.GUIDToAssetPath(guid);
    EnemyData data = AssetDatabase.LoadAssetAtPath<EnemyData>(path);
    if (data == null) continue;

    // Set attackDamage based on enemy type / existing maxHealth
    int dmg = 0;
    if (data.stats.attackDamage <= 0)
    {
        // Derive from maxHealth: weak enemies ~2, medium ~5, strong ~8, boss ~15
        if (data.stats.isBoss)
            dmg = 15;
    else if (data.stats.maxHealth >= 200)
            dmg = 8;
        else if (data.stats.maxHealth >= 100)
            dmg = 5;
        else if (data.stats.maxHealth >= 50)
            dmg = 3;
        else
            dmg = 2;

        var stats = data.stats;
        stats.attackDamage = dmg;
        data.stats = stats;
        EditorUtility.SetDirty(data);
        Debug.Log($"Set {data.enemyName} ({path}) attackDamage={dmg} (HP={data.stats.maxHealth})");
        count++;
    }
}
AssetDatabase.SaveAssets();
Debug.Log($"Updated {count} EnemyData assets with attackDamage");

