foreach (var c in canvases)
{
    Debug.Log($"=== Canvas: {c.name} (renderMode={c.renderMode}, sortingOrder={c.sortingOrder}) ===");
    PrintHierarchy(c.transform, 0, 3);
}

void PrintHierarchy(Transform t, int indent, int maxDepth)
{
    string prefix = new string(' ', indent * 2);
    var img = t.GetComponent<UnityEngine.UI.Image>();
    var txt = t.GetComponent<UnityEngine.UI.Text>();
    var btn = t.GetComponent<UnityEngine.UI.Button>();
    string info = "";
    if (img != null && img.sprite != null) info += $" [Img:{img.sprite.name}]";
    if (txt != null) info += $" [Txt:\"{txt.text}\"]";
    if (btn != null) info += " [Btn]";
    Debug.Log($"{prefix}{t.name}{info}");

    if (indent < maxDepth)
    {
        for (int i = 0; i < t.childCount; i++)
            PrintHierarchy(t.GetChild(i), indent + 1, maxDepth);
    }
}

