using UnityEngine;
using UnityEngine.UI;

// ========================================
// Kingdom Rush Style HUD - Top Bar Redesign
// ========================================
// Color palette: dark wood, gold accents, warm tones

var canvas = GameObject.Find("画布");
if (canvas == null) { Debug.LogError("Canvas not found!"); return; }

var topBar = canvas.transform.Find("顶部标题栏");
if (topBar == null) { Debug.LogError("Top bar not found!"); return; }

// ---- 1. Style the top bar background ----
var barRect = topBar.GetComponent<RectTransform>();
barRect.anchorMin = new Vector2(0, 1);
barRect.anchorMax = new Vector2(1, 1);
barRect.pivot = new Vector2(0.5f, 1);
barRect.anchoredPosition = new Vector2(0, 0);
barRect.sizeDelta = new Vector2(0, 70);

var barImg = topBar.GetComponent<UnityEngine.UI.Image>();
if (barImg == null) barImg = topBar.gameObject.AddComponent<UnityEngine.UI.Image>();
// Dark wood gradient: top=#1A0E08, bottom=#3D1F0B
barImg.color = new Color(0.18f, 0.1f, 0.05f, 0.95f);

// Add bottom border (gold line)
var borderObj = new GameObject("GoldBorder");
borderObj.transform.SetParent(topBar, false);
var borderRect = borderObj.GetComponent<RectTransform>();
borderRect.anchorMin = new Vector2(0, 0);
borderRect.anchorMax = new Vector2(1, 0);
borderRect.pivot = new Vector2(0.5f, 0);
borderRect.sizeDelta = new Vector2(0, 3);
borderRect.anchoredPosition = Vector2.zero;
var borderImg = borderObj.AddComponent<UnityEngine.UI.Image>();
borderImg.color = new Color(0.77f, 0.59f, 0.23f, 1f); // Gold #C4963C

// ---- 2. Style Gold display ----
var goldObj = topBar.Find("金币");
if (goldObj != null)
{
    var goldRect = goldObj.GetComponent<RectTransform>();
    goldRect.anchorMin = new Vector2(0, 0.5f);
    goldRect.anchorMax = new Vector2(0, 0.5f);
    goldRect.pivot = new Vector2(0, 0.5f);
    goldRect.anchoredPosition = new Vector2(15, 0);
    goldRect.sizeDelta = new Vector2(160, 44);

    // Gold background pill
    var goldBg = goldObj.GetComponent<UnityEngine.UI.Image>();
    if (goldBg == null) goldBg = goldObj.gameObject.AddComponent<UnityEngine.UI.Image>();
    goldBg.color = new Color(0.1f, 0.06f, 0.02f, 0.8f);

    // Gold icon
    var goldIcon = goldObj.Find("Image");
    if (goldIcon != null)
    {
        var iconRect = goldIcon.GetComponent<RectTransform>();
        iconRect.anchorMin = new Vector2(0, 0.5f);
        iconRect.anchorMax = new Vector2(0, 0.5f);
        iconRect.pivot = new Vector2(0, 0.5f);
        iconRect.sizeDelta = new Vector2(32, 32);
        iconRect.anchoredPosition = new Vector2(8, 0);
        var iconImg = goldIcon.GetComponent<UnityEngine.UI.Image>();
        if (iconImg != null) iconImg.color = new Color(1f, 0.84f, 0f, 1f); // Gold coin yellow
    }

    // Gold text
    var goldText = goldObj.Find("GoldText");
    if (goldText != null)
    {
        var txtRect = goldText.GetComponent<RectTransform>();
        txtRect.anchorMin = new Vector2(0, 0);
