        ir.anchoredPosition = new Vector2(8, 0);
        var ii = goldIcon.GetComponent<Image>();
        if (ii != null) ii.color = new Color32(255, 214, 0, 255);
    }
    var goldText = goldObj.Find("GoldText");
    if (goldText != null) {
        var tr = goldText.GetComponent<RectTransform>();
        tr.anchorMin = new Vector2(0, 0); tr.anchorMax = new Vector2(1, 1);
        tr.sizeDelta = new Vector2(-48, 0); tr.anchoredPosition = new Vector2(48, 0);
        var t = goldText.GetComponent<Text>();
        if (t != null) { t.fontSize = 24; t.fontStyle = FontStyle.Bold; t.color = new Color32(255, 214, 0, 255); t.alignment = TextAnchor.MiddleLeft; }
    }
}

