    lifeRect.anchorMin = new Vector2(0, 0.5f);
    lifeRect.anchorMax = new Vector2(0, 0.5f);
    lifeRect.pivot = new Vector2(0, 0.5f);
    lifeRect.anchoredPosition = new Vector2(190, 0);
    lifeRect.sizeDelta = new Vector2(120, 44);
    var lifeBg = lifeObj.GetComponent<Image>();
    if (lifeBg == null) lifeBg = lifeObj.gameObject.AddComponent<Image>();
    lifeBg.color = new Color32(26, 15, 5, 204);
    var lifeIcon = lifeObj.Find("Image");
    if (lifeIcon != null) {
        var ir = lifeIcon.GetComponent<RectTransform>();
        ir.anchorMin = new Vector2(0, 0.5f); ir.anchorMax = new Vector2(0, 0.5f);
        ir.pivot = new Vector2(0, 0.5f); ir.sizeDelta = new Vector2(28, 28);
        ir.anchoredPosition = new Vector2(8, 0);
        var ii = lifeIcon.GetComponent<Image>();
        if (ii != null) ii.color = new Color32(230, 51, 51, 255);
    }
    var lifeText = lifeObj.Find("LifeText");
    if (lifeText != null) {
        var tr = lifeText.GetComponent<RectTransform>();
        tr.anchorMin = new Vector2(0, 0); tr.anchorMax = new Vector2(1, 1);
        tr.sizeDelta = new Vector2(-44, 0); tr.anchoredPosition = new Vector2(44, 0);
        var t = lifeText.GetComponent<Text>();
        if (t != null) { t.fontSize = 24; t.fontStyle = FontStyle.Bold; t.color = new Color32(255, 102, 102, 255); t.alignment = TextAnchor.MiddleLeft; }
    }
}

// Style Wave
var waveObj = topBar.Find("WaveText");
if (waveObj != null) {
