    var enemyText = enemyObj.GetComponent<Text>();
    if (enemyText != null) { enemyText.fontSize = 20; enemyText.fontStyle = FontStyle.Bold; enemyText.color = new Color32(217, 140, 77, 255); enemyText.alignment = TextAnchor.MiddleCenter; }
